# 4. 4 бүлгээр ангилах ухаалаг функц
def утгаар_ангилах(утга):
    # Хэрэв хоосон эсвэл NaN бол
    if pd.isna(утга) or утга == '':
        return 'Цуцалсан'
    
    # Хэрэв утга нь Datetime (огноо) эсвэл тоо байвал шууд ХҮРГЭСЭН болно
    if isinstance(утга, (pd.Timestamp, type(pd.NaT))) or 'datetime' in str(type(утга)):
        return 'Хүргэсэн'
    
    # Текстийг жижиг үсгээр, зайг нь устгаж шалгах
    цэвэр_утга = str(утга).strip().lower()
    
    # Тусгайлан цуцлах ёстой 4 үг (Шууд Цуцалсан)
    тусгай_цуцлах_үгс = [
        'аптекаас авсан', 'ooriig awtsan', 'жолоочид хувиарласан',
        'дээлгүүрт үлдээ гээд үлдээсэн боловч утсаа аваагүй буцав'
    ]
    if цэвэр_утга in тусгай_цуцлах_үгс or 'дэлгүүрт үлдээ' in цэвэр_утга:
        return 'Цуцалсан'
        
    # Дөрвөн бүлгийн шалгалт
    if цэвэр_утга in хүргэсэн_үгс:
        return 'Хүргэсэн'
    elif цэвэр_утга in буцаасан_үгс:
        return 'Буцаасан'
    elif цэвэр_утга in хойшлогдсон_үгс:
        return 'Хойшлогдсон захиалга'
    else:
        # Дээрх жагсаалтуудад ороогүй бусад холбогдоогүй, хаяг буруу гэх мэт утгууд шууд Цуцалсан болно
        return 'Цуцалсан'

